checkfiledownload.usage:
-- Only allow downloads for the chip owner. This will cause require()/dofile() to throw an error for other players. 
hook.add( "checkfiledownload", "Deny non-owner", function( Ply, FileName ) 
	print( Ply:nick(), "attempted to download file:", FileName ) 
	return Ply == ents.owner() 
end )

